class Solution:
    def lexGreaterPermutation(self, s, target):
        from collections import Counter
        n = len(s)
        cnt = Counter(s)
        res = [None]
        def dfs(pos, tight, acc):
            if res[0] is not None:
                return
            if pos == n:
                cand = ''.join(acc)
                if cand > target:
                    res[0] = cand
                return
            for c in sorted(k for k in cnt if cnt[k] > 0):
                if tight and c < target[pos]:
                    continue
                cnt[c] -= 1
                acc.append(c)
                dfs(pos + 1, tight and c == target[pos], acc)
                acc.pop()
                cnt[c] += 1
                if res[0] is not None:
                    return
        dfs(0, True, [])
        return res[0] if res[0] is not None else ''

