class Solution:
    def lexGreaterPermutation(self, s, target):
        from collections import Counter
        n = len(s)
        cnt = Counter(s)
        best = None
        for p in range(n - 1, -1, -1):
            temp = Counter(cnt)
            ok = True
            for i in range(p):
                if temp[target[i]] <= 0:
                    ok = False
                    break
                temp[target[i]] -= 1
            if not ok:
                continue
            chosen = None
            for c in sorted(temp):
                if c > target[p] and temp[c] > 0:
                    chosen = c
                    break
            if chosen is None:
                continue
            temp[chosen] -= 1
            rest = ''.join(c * temp[c] for c in sorted(temp))
            cand = target[:p] + chosen + rest
            if best is None or cand < best:
                best = cand
        return best if best is not None else ''

