var lexGreaterPermutation = function(s, target) {
    const n = s.length;
    const base = new Array(26).fill(0);
    for (const ch of s) base[ch.charCodeAt(0) - 97]++;
    let best = null;
    for (let p = n - 1; p >= 0; p--) {
        const temp = base.slice();
        let ok = true;
        for (let i = 0; i < p; i++) {
            const idx = target.charCodeAt(i) - 97;
            if (temp[idx] <= 0) { ok = false; break; }
            temp[idx]--;
        }
        if (!ok) continue;
        const tp = target.charCodeAt(p) - 97;
        let chosen = -1;
        for (let c = tp + 1; c < 26; c++) {
            if (temp[c] > 0) { chosen = c; break; }
        }
        if (chosen === -1) continue;
        temp[chosen]--;
        let rest = '';
        for (let c = 0; c < 26; c++) rest += String.fromCharCode(97 + c).repeat(temp[c]);
        const cand = target.slice(0, p) + String.fromCharCode(97 + chosen) + rest;
        if (best === null || cand < best) best = cand;
    }
    return best === null ? '' : best;
};
